import React from "react";
import { getImage } from "../../utils/getImage";

export default function Grid({
  items,
  selectedId,
  onSelect,
  hoveredId,
  setHovered,
  isSingle,
}) {
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: isSingle
          ? "repeat(auto-fit, minmax(260px, 1fr))"
          : "repeat(auto-fill, minmax(220px, 1fr))",
        gap: "14px",
      }}
    >
      {items.map((item) => {
        const isSelected = selectedId === item.id;

        return (
          <button
            key={item.id}
            onClick={() => onSelect(item)}
            onMouseEnter={() => setHovered(item.id)}
            onMouseLeave={() => setHovered(null)}
            style={{
              all: "unset",
              cursor: "pointer",
              display: "block",
            }}
          >
            {/* TARJETA */}
            <div
              style={{
                position: "relative",
                width: "100%",
                aspectRatio: "1 / 1", // 🔥 CLAVE: cuadrado uniforme
                borderRadius: "12px",
                overflow: "hidden",
                background: "#eee",
                boxShadow: isSelected
                  ? "0 0 0 2px #0b1f4d"
                  : "0 4px 12px rgba(0,0,0,0.08)",
                transition: "all 0.2s ease",
                transform:
                  hoveredId === item.id ? "scale(1.02)" : "scale(1)",
              }}
            >
              {/* IMAGEN */}
              <img
                src={getImage(item, "thumb")}
                alt={item.titulo}
                loading="lazy"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover", // 🔥 recorta pero mantiene proporción
                }}
              />

              {/* OVERLAY (opcional pero recomendable) */}
              <div
                style={{
                  position: "absolute",
                  inset: 0,
                  background:
                    hoveredId === item.id
                      ? "rgba(0,0,0,0.15)"
                      : "rgba(0,0,0,0)",
                  transition: "background 0.2s ease",
                }}
              />

              {/* TÍTULO */}
              <div
                style={{
                  position: "absolute",
                  bottom: 0,
                  left: 0,
                  right: 0,
                  padding: "8px 10px",
                  fontSize: "12px",
                  color: "#fff",
                  background:
                    "linear-gradient(to top, rgba(0,0,0,0.6), transparent)",
                  opacity: hoveredId === item.id ? 1 : 0,
                  transition: "opacity 0.2s ease",
                }}
              >
                {item.titulo}
              </div>
            </div>
          </button>
        );
      })}
    </div>
  );
}
